      showNotification("Berjaya Ditebus!", "Tahniah! 500 Kredit telah dimasukkan ke dalam akaun anda.", "success");
      setVoucherCode('');
    } else {
      showNotification("Tidak Sah", "Maaf, kod baucar ini tidak wujud atau telah tamat tempoh.", "error");
    }
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen overflow-hidden bg-slate-50 text-slate-800 w-full font-sans relative">

      {/* UI NOTIFICATION UMUM (Pop-up Warning/Error/Info) */}
      {notification.show && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white p-8 rounded-[2rem] shadow-2xl max-w-sm w-full text-center animate-in zoom-in-95 duration-300 border border-slate-100">
            <div className="flex justify-center mb-5">
              {notification.type === 'warning' ? <AlertCircle size={56} className="text-amber-500" /> :
               notification.type === 'error' ? <XCircle size={56} className="text-red-500" /> :
               <CheckCircle2 size={56} className="text-green-500" />}
            </div>
            <h3 className="text-xl font-black text-slate-800 mb-2">{notification.title}</h3>
            <p className="text-slate-500 font-medium mb-8 text-sm leading-relaxed">{notification.message}</p>
            <button 
              onClick={() => setNotification({ ...notification, show: false })} 
              className="w-full py-3.5 bg-slate-900 text-white rounded-2xl font-black tracking-wide hover:bg-slate-800 transition-colors active:scale-95"
            >
              Tutup
            </button>
          </div>
        </div>
      )}

      {/* UI NOTIFICATION KEMPEN SELESAI (Pop-up Blast Result) */}
      {blastResultModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] shadow-2xl max-w-md w-full overflow-hidden animate-in zoom-in-95 duration-500 border border-slate-100">
            <div className="bg-green-500 p-8 text-center text-white relative overflow-hidden">
              <div className="relative z-10 flex justify-center mb-4">
                <div className="w-20 h-20 bg-white/20 rounded-full flex items-center justify-center backdrop-blur-md shadow-inner border border-white/30">
                  <CheckCircle2 size={40} className="text-white drop-shadow-md" />
                </div>
              </div>
              <h3 className="text-3xl font-black relative z-10 tracking-tight mb-1">Kempen Selesai</h3>
              <p className="text-green-100 font-medium relative z-10 text-sm">Laporan penghantaran mesej</p>
              <Send className="absolute -right-6 -bottom-6 opacity-10 rotate-12 scale-150" size={120}/>
            </div>
            <div className="p-8">
              <div className="flex gap-4 mb-6">
                <div className="text-center bg-green-50 p-4 rounded-2xl flex-1 border border-green-100 shadow-sm">
                  <p className="text-[10px] font-black text-green-600 uppercase tracking-widest mb-1">Berjaya</p>
                  <p className="text-4xl font-black text-green-600">{blastResultModal.success}</p>
                </div>
                <div className="text-center bg-red-50 p-4 rounded-2xl flex-1 border border-red-100 shadow-sm">
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest mb-1">Gagal</p>
                  <p className="text-4xl font-black text-red-500">{blastResultModal.failed}</p>
                </div>
              </div>
              <div className="bg-slate-50 p-4 rounded-2xl mb-8 border border-slate-100">
                <p className="text-xs text-slate-500 font-medium text-center leading-relaxed">
                  *Nombor yang mencatatkan status gagal berkemungkinan besar tidak mempunyai akaun WhatsApp aktif atau dilarang oleh pihak pelayan.
                </p>
              </div>
              <button 
                onClick={() => {
                  setBlastResultModal({ isOpen: false, success: 0, failed: 0 });
                  setActiveTab('dashboard'); // Auto redirect ke dashboard
                }} 
                className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-slate-800 transition-all active:scale-95 shadow-xl shadow-slate-200"
              >
