                    >
                      Tebus Kod
                    </button>
                  </div>
                </div>
              </div>

              {/* BANTUAN KHAS */}
              <div className="bg-slate-900 rounded-[3rem] p-10 flex flex-col md:flex-row items-center justify-between gap-6 text-white shadow-2xl relative overflow-hidden mt-12">
